        private void SetStatLabel(Label lbl, int x, int y, Font f, Color c, string text)
        {
            lbl.AutoSize = false;
            lbl.Font = f;
            lbl.ForeColor = c;
            lbl.BackColor = Color.Transparent;
            lbl.Location = new Point(x, y);
            lbl.Size = new Size(440, 28);
            lbl.Text = text;
        }

